SELECT "product"."category_id" AS "categoryId", SUM(("orderItem"."unit_price" * "orderItem"."quantity")) AS "revenue", SUM("orderItem"."quantity") AS "totalQuantity", COUNT(*) AS "lineCount", AVG("orderItem"."unit_price") AS "avgItemPrice" FROM "order_items" AS "orderItem" LEFT JOIN "orders" AS "order" ON ("orderItem"."order_id" = "order"."id") LEFT JOIN "products" AS "product" ON ("orderItem"."product_id" = "product"."id") WHERE ("order"."created_at" BETWEEN ? AND ?) GROUP BY "product"."category_id" HAVING ((? IS NULL) OR ("revenue" >= ?)) ORDER BY "revenue" DESC NULLS LAST LIMIT ?
